	public dictionar_cuvinte(string language)
	{
		switch (language)
		{
		case "Română":
			dictionar = dictionar_ro;
			break;
		case "English":
			dictionar = dictionar_eng;
			break;
		case "Polski":
			dictionar = dictionar_pl;
			break;
		default:
			dictionar = dictionar_eng;
			break;
		}
	}
}
